#include<bits/stdc++.h>
using namespace std;
long long fac[200010],ifac[200010];
const long long mod=1e9+7;
long long fastpow(long long a,long long b,long long mod)
{
    long long ans=1;
    while(b)
    {
        if(b%2==1)
        {
            ans=ans*a%mod;
        }
        a=a*a%mod;
        b/=2;
    }
    return ans;
}
long long C(int n,int m)
{
    if(n==m||m==0)
    {
        return 1;
    }
    return(fac[n]*ifac[m]%mod*ifac[n-m]%mod);
}
int main()
{
    int n,m,a,b;
    scanf("%d%d%d%d",&n,&m,&a,&b);
    fac[1]=1;
    for(int i=2;i<=200000;i++)
    {
        fac[i]=fac[i-1]*i%mod;
    }
    ifac[200000]=fastpow(fac[200000],mod-2,mod);
    for(int i=199999;i>=1;i--)
    {
        ifac[i]=fastpow(fac[i],mod-2,mod);
    }
    long long ans=0;
    for(int i=1;i<=n-a;i++)
    {
        ans+=(C(i+b-2,i-1)*C(n+m-i-b-1,n-i))%mod;
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
